sql:
SELECT centre_code, COUNT(review_id) AS number_of_reviews
FROM parent_reviews
GROUP BY centre_code;

SELECT operating_model, AVG(rating) AS average_rating
FROM childcare_centres
GROUP BY operating_model;

SELECT centre_name, rating
FROM childcare_centres
ORDER BY rating DESC;

SELECT centre_name
FROM childcare_centres
ORDER BY centre_name ASC;

SELECT COUNT(*) 
FROM subsidies 
WHERE subsidy_type = 'Government Subsidy';

SELECT centre_name, centre_address, rating
FROM childcare_centres
ORDER BY rating DESC;
